  ('social-worker-moex-00465', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在社會正義相關的哲學討論中，提出差異原則的學者是下列何者？', '["羅爾斯（JohnRawls）", "諾齊克（RobertNozick）", "沈思（AmartyaSen）", "海耶克（FriedrichA.Hayek）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00466', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何種敘述不是馬克思主義所強調的重點？', '["認為資本主義國家必須要滿足資本累積和政治合法性兩者互相矛盾的功能", "認為福利國家是一種社會控制的手段", "福利制度是為了回應世代之間衝突", "社會福利會讓人民形成虛假意識"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00467', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '撰寫到奴役之路（TheRoadtoSerfdom），認為政府所推動的公共福利是對自由造成侵害，該學者 為下列何者？', '["伯林（lsaiahBerlin）", "海耶克（FriedrichHayek）", "斯密（AdamSmith）", "傅利曼（MiltonFriedman）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00468', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '布蘭蕭（J.Bradshaw）提出福利服務輸送的四種需求類型，其中將需求感受付諸於行動，這是屬 於何種需求？', '["規範性需求", "表達性需求", "比較性需求", "感覺性需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00469', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1601年英國的「伊莉莎白43號」法案，強調「親屬責任」的精神下，確立並統整既有三大救濟 體系，下列何者非其措施？', '["對懶惰者加以懲罰", "對羸弱者收容在濟貧院中", "對身體健壯者要求工作", "依麵包價格與家庭人口，補貼工資之不足"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00470', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '美國近代的社會政策發展中，下列相關重要社會政策敘述，何者錯誤？', '["1935年通過「社會安全法案」，為美國當前社會福利的基礎", "美國詹森（Johnson）總統於1964年開啟對貧窮作戰計畫", "1965年之「醫療補助」（Medicaid）方案，主要提供老人健康保險，由民間經營，政府補助行 政費用", "1996年克林頓（Clinton）政府簽署「個人責任與工作機會協調法案」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
